#include <bits/stdc++.h>
using namespace std;

const int N=5e4+10,M=2e7+10;

int n,m,ans;
int head[N],ver[M],nxt[M],tot=1,f[N*2],q[N*2],hh,tt;
int dfn[N],low[N],num,stk[N],top,now;
vector<int> e[2*N];

void add(int x,int y){
    ver[++tot]=y,nxt[tot]=head[x],head[x]=tot;
    ver[++tot]=x,nxt[tot]=head[y],head[y]=tot;
}

void tarjan(int x){
    dfn[x]=low[x]=++num;
    stk[++top]=x;
    for(int i=head[x],y;i;i=nxt[i]){
        y=ver[i];
        if(!dfn[y]){
            tarjan(y);
            low[x]=min(low[x],low[y]);
            if(low[y]>=dfn[x]){
                int z;
                now++;
                do{
                    z=stk[top--];
                    e[z].push_back(now);
                    e[now].push_back(z);
//                    printf("%d %d\n",now,z);
                }while(z!=y);
                e[x].push_back(now);
                e[now].push_back(x);
//                printf("%d %d\n",now,x);
            }
        }else
            low[x]=min(low[x],dfn[y]);
    }
}

void dfs(int x,int fa){
    for(int y:e[x])
        if(y!=fa)
            dfs(y,x);
    if(x<=n)
        return;
    int len=e[x].size(),pf;
    for(int i=0;i<len;i++)
        if(e[x][i]==fa){
            pf=i;
            break;
        }
//	printf("To %d\n",x);
    hh=1,tt=0;
    int mx=-1e9,mxf=-1e9;
    for(int i=1,y;i<len;i++){
        y=e[x][(i+pf)%len];
        ans=max(ans,f[fa]+f[y]+min(i,len-i));
//        printf("%d %d %d\n",fa,y,f[fa]+f[y]+min(i,len-i));
        mxf=max(mxf,f[y]+min(i,len-i));
        while(hh<=tt && i-q[hh]>len/2){
            mx=max(mx,q[hh]+f[e[x][(q[hh]+pf)%len]]);
            hh++;
        }
        ans=max(ans,f[y]+len-i+mx);
//        printf("%d %d\n",y,f[y]+len-i+mx);
        if(hh<=tt){
            ans=max(ans,f[y]+f[e[x][(q[hh]+pf)%len]]+i-q[hh]);
//            printf("n %d %d %d\n",y,e[x][(q[hh]+pf)%len],f[y]+f[e[x][(q[hh]+pf)%len]]+i-q[hh]); 
        }
        while(hh<=tt && f[e[x][(q[tt]+pf)%len]]-q[tt]<=f[y]-i)
            tt--;
        q[++tt]=i;
    }
    f[fa]=max(f[fa],mxf);
}


int main(){
    scanf("%d%d",&n,&m);
    for(int i=1;i<=m;i++){
        int k,x,lst=0;
        scanf("%d",&k);
        while(k--){
            scanf("%d",&x);
            if(lst)
                add(lst,x);
            lst=x;
        }
    }
    now=n;
    tarjan(1);
    dfs(1,0);
    printf("%d",ans);
    return 0;
}
